	static NativeTupleDistinctPlan tuple(SlotPlan arg, int[] keySlots, RowState row) {
		if (!SlotPlan.encounterOrderReplaySafe(arg)) {
			return NativeTupleDistinctPlan.global(arg, keySlots);
		}
		if (keySlots.length == 0) {
			return new NativeTupleDistinctPlan(arg, NativeDistinctStrategy.ADJACENT, keySlots, new int[0], new int[0]);
		}
		NativeOrderedPlan best = new NativeOrderedPlan(arg, NativeSlotOrder.NONE);
		int[] bestPrefix = new int[0];
		List<int[]> signatures = permutations(unique(keySlots));
		for (int[] signature : signatures) {
			NativeOrderedPlan candidate = best(arg, signature, row);
			int[] prefix = candidate.order.leadingKeySlots(keySlots, candidate.plan.producedMask());
			if (prefix.length > bestPrefix.length
					|| (prefix.length == bestPrefix.length && betterEstimate(candidate, best, row))) {
				best = candidate;
				bestPrefix = prefix;
			}
		}
		long varying = NativeSlotOrder.mask(keySlots) & arg.producedMask() & ~best.order.fixedMask;
		long covered = NativeSlotOrder.mask(bestPrefix);
		if ((varying & ~covered) == 0L) {
			return new NativeTupleDistinctPlan(best.plan, NativeDistinctStrategy.ADJACENT, keySlots, bestPrefix,
					new int[0]);
		}
		if (bestPrefix.length == 0) {
			return NativeTupleDistinctPlan.global(arg, keySlots);
		}
		return new NativeTupleDistinctPlan(best.plan, NativeDistinctStrategy.PARTITIONED_HASH, keySlots, bestPrefix,
				without(keySlots, bestPrefix, best.order.fixedMask));
	}

